# @cctt_verify {"v":2,"sym":"sympy.core.tests.test_relational.rel_check","kind":"function","src_hash":"d54e14b0c6196c70","in":{"base":"Any"},"out":{"base":"Any","pred":"a.is_number and b.is_number and len(set(v)) == 1 and v[0] == False and not a != b and (not a == b) and raises(TypeError, lambda: a < b) and raises(TypeError, lambda: a <= b) and raises(TypeError, lambda: a > b) and raises(TypeError, lambda: a >= b) and len(set(E)) == 2 and E[0] or a.is_Float != b.is_Float and E[1]"},"spec":{"lhs":"rel_check(a, )","rhs":"rel_check produces the expected output","over":{"base":"Any"},"name":"rel_check_correct"},"guarantee":"rel_check produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.core.tests.test_relational.rel_check_correct","statement":"Path(rel_check(x), rel_check produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"3c149cf19b41baf0"}
def rel_check(a, b):
    from sympy.testing.pytest import raises
    assert a.is_number and b.is_number
    for do in range(len({type(a), type(b)})):
        if S.NaN in (a, b):
            v = [(a == b), (a != b)]
            assert len(set(v)) == 1 and v[0] == False
            assert not (a != b) and not (a == b)
            assert raises(TypeError, lambda: a < b)
            assert raises(TypeError, lambda: a <= b)
            assert raises(TypeError, lambda: a > b)
            assert raises(TypeError, lambda: a >= b)
        else:
            E = [(a == b), (a != b)]
            assert len(set(E)) == 2
            v = [
            (a < b), (a <= b), (a > b), (a >= b)]
            i = [
            [True,    True,     False,   False],
            [False,   True,     False,   True], # <-- i == 1
            [False,   False,    True,    True]].index(v)
            if i == 1:
                assert E[0] or (a.is_Float != b.is_Float) # ugh
            else:
                assert E[1]
        a, b = b, a
    return True


