# @cctt_verify {"v":2,"sym":"sympy.core.tests.test_relational.test_x_minus_y_not_same_as_x_lt_y","kind":"function","src_hash":"9d07f59e95af26fa","in":{"base":"Any"},"out":{"base":"Any","pred":"x - y < 0 and ineq.lhs - ineq.rhs < 0 and ineq.lhs - ineq.rhs < 0"},"spec":{"lhs":"test_x_minus_y_not_same_as_x_lt_y()","rhs":"a consequence of pull request #7792 is that `x - y < 0` and `x < y` are not synonymous","over":{"base":"Any"},"name":"test_x_minus_y_not_same_as_x_lt_y_correct"},"guarantee":"a consequence of pull request #7792 is that `x - y < 0` and `x < y` are not synonymous","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.core.tests.test_relational.test_x_minus_y_not_same_as_x_lt_y_correct","statement":"Path(test_x_minus_y_not_same_as_x_lt_y(x), a consequence of pull request #7792 is that `x - y < 0` and `x < y` are not synonymous)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"d0e1dc655efda1df"}
def test_x_minus_y_not_same_as_x_lt_y():
    """
    A consequence of pull request #7792 is that `x - y < 0` and `x < y`
    are not synonymous.
    """
    x = I + 2
    y = I + 3
    raises(TypeError, lambda: x < y)
    assert x - y < 0

    ineq = Lt(x, y, evaluate=False)
    raises(TypeError, lambda: ineq.doit())
    assert ineq.lhs - ineq.rhs < 0

    t = Symbol('t', imaginary=True)
    x = 2 + t
    y = 3 + t
    ineq = Lt(x, y, evaluate=False)
    raises(TypeError, lambda: ineq.doit())
    assert ineq.lhs - ineq.rhs < 0

    # this one should give error either way
    x = I + 2
    y = 2*I + 3
    raises(TypeError, lambda: x < y)
    raises(TypeError, lambda: x - y < 0)


