# @cctt_verify {"v":2,"sym":"sympy.core.tests.test_relational.test_improved_canonical","kind":"function","src_hash":"c78f29a3bcf90436","in":{"base":"Any"},"out":{"base":"Any","pred":"(pi >= x).canonical == (x <= pi) and form1.canonical == form2.canonical"},"spec":{"lhs":"test_improved_canonical()","rhs":"test_improved_canonical produces the expected output","over":{"base":"Any"},"name":"test_improved_canonical_correct"},"guarantee":"test_improved_canonical produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.core.tests.test_relational.test_improved_canonical_correct","statement":"Path(test_improved_canonical(x), test_improved_canonical produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"1c6ee49444002c0c"}
def test_improved_canonical():
    def test_different_forms(listofforms):
        for form1, form2 in combinations(listofforms, 2):
            assert form1.canonical == form2.canonical

    def generate_forms(expr):
        return [expr, expr.reversed, expr.reversedsign,
                expr.reversed.reversedsign]

    test_different_forms(generate_forms(x > -y))
    test_different_forms(generate_forms(x >= -y))
    test_different_forms(generate_forms(Eq(x, -y)))
    test_different_forms(generate_forms(Ne(x, -y)))
    test_different_forms(generate_forms(pi < x))
    test_different_forms(generate_forms(pi - 5*y < -x + 2*y**2 - 7))

    assert (pi >= x).canonical == (x <= pi)


